(window.webpackJsonp=window.webpackJsonp||[]).push([[4],{361:function(t,e){"use strict";e.__esModule=!0,e.default={render:function(){return this.$createElement("div",{staticClass:"theme-default-content content__default",domProps:{innerHTML:"<h1 id=\"成员\"><a href=\"#成员\" class=\"header-anchor\">#</a> 成员</h1>\n<h2 id=\"导师\"><a href=\"#导师\" class=\"header-anchor\">#</a> 导师</h2>\n<div class=\"row\"><div class=\"column\"><img src=\"/src/img/vital_logo.svg\" alt=\"VITAL Lab\"> <a href=\"https://jiongzhang-john.github.io/\" target=\"_blank\" rel=\"noopener noreferrer\">张炯 / Jiong Zhang</a> <div>教授，课题组负责人</div> <div>Vascular Imaging and Translational AI Laboratory</div> <a href=\"mailto:jiong.zhang@ieee.org\">jiong.zhang@ieee.org</a> <div><a href=\"https://people.ucas.ac.cn/~jiong.zhang\" target=\"_blank\" rel=\"noopener noreferrer\">国科大主页</a> · <a href=\"https://scholar.google.com/citations?user=UJKsxKkAAAAJ&hl=en\" target=\"_blank\" rel=\"noopener noreferrer\">Google Scholar</a></div></div></div>\n<h2 id=\"研究团队\"><a href=\"#研究团队\" class=\"header-anchor\">#</a> 研究团队</h2>\n<p>VITAL Lab 欢迎对血管影像、医学影像分析、OCT/OCTA、图学习、图像分割、疾病标志物发现和转化人工智能感兴趣的同学与合作者。</p>\n<h2 id=\"开放岗位\"><a href=\"#开放岗位\" class=\"header-anchor\">#</a> 开放岗位</h2>\n<ul><li>招收具有计算机、 biomedical engineering、医学影像或相关背景的博士生、硕士生。</li><li>欢迎医学影像计算、临床 AI 系统方向的科研助理和实习生加入。</li><li>欢迎医院、影像中心和生命科学研究团队开展交叉合作。</li></ul>\n<p>课题组其他成员信息将在名单确认后继续更新。</p>"}})}}}}]);
